@receiver(pre_save, sender=Withdrawal)
def track_withdrawal_status_change(sender, instance, **kwargs):
    """Track old status before save"""
    if instance.pk:
        try:
            instance._old_status = Withdrawal.objects.get(pk=instance.pk).status
        except Withdrawal.DoesNotExist:
            instance._old_status = None
    else:
        instance._old_status = None


@receiver(post_save, sender=Withdrawal)
def notify_withdrawal_status_change(sender, instance, created, **kwargs):
    """Send notification when withdrawal status changes"""
    # Skip if just created
    if created:
        return

    # Check if status changed
    old_status = getattr(instance, '_old_status', None)
    if old_status == instance.status:
        return

    user = instance.user

    if instance.status == 'completed':
        # Send email to user
        try:
            send_withdrawal_completed_email(instance)
            logger.info(f"Withdrawal {instance.id} completed email sent to {user.email}")
        except Exception as e:
            logger.error(f"Failed to send withdrawal completion email: {str(e)}")

"""
Custom authentication backend to allow login with email OR username
"""
from django.contrib.auth.backends import ModelBackend
from django.contrib.auth import get_user_model
from django.db.models import Q

User = get_user_model()


class EmailOrUsernameBackend(ModelBackend):
    """
    Custom authentication backend that allows users to login with either
    their email address or a username field (if it exists).

    For admin users, also checks if input matches 'admin' as a shortcut.
    """

    def authenticate(self, request, username=None, password=None, **kwargs):
        if username is None or password is None:
            return None

        # Normalize input
        username = username.strip().lower()

        try:
            # Try to find user by email first
            user = User.objects.get(email__iexact=username)
        except User.DoesNotExist:
            # If not found by email, check if it's 'admin' shortcut for superuser
            if username == 'admin':
                try:
                    user = User.objects.get(is_superuser=True, email__icontains='admin')
                except User.DoesNotExist:
                    return None
                except User.MultipleObjectsReturned:
                    # Multiple admin accounts, try the first one
                    user = User.objects.filter(is_superuser=True, email__icontains='admin').first()
            else:
                # No user found
                return None

        # Check password and if user can authenticate
        if user.check_password(password) and self.user_can_authenticate(user):
            return user

        return None

    def get_user(self, user_id):
        try:
            return User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return None

